SELECT * FROM inpatient_fee
WHERE deleted = 0

    AND (patient_name LIKE CONCAT('%', #{keyword}, '%') OR inpatient_no LIKE CONCAT('%', #{keyword}, '%') OR fee_name LIKE CONCAT('%', #{keyword}, '%'))


    AND inpatient_id = #{inpatientId}


    AND fee_date = #{feeDate}

ORDER BY fee_date DESC, create_time DESC
